const PROCESSING_FEE = 5;

type Scenario = { customer: { yearsWithMHPCO: number }; steps: Array<{ op: string; items?: unknown[] }> };

export const runScenario = (scenario: unknown): unknown => {
  const s = scenario as Scenario;
  const results = s.steps.map((step) => {
    const items = step.items ?? [];
    const base = items.length === 0 ? 0 : 100;
    return { premium: base + PROCESSING_FEE };
  });
  return { results };
};

