const PROCESSING_FEE = 5;
const DEFAULT_BASE_PREMIUM = 100;

type QuoteItem = { type: string; material: string; enchantment: number; cursed: boolean };
type Step = { op: string; items: QuoteItem[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
  amulet: 60,
};

const basePremiumForItem = (item: QuoteItem): number =>
  BASE_PREMIUM_BY_TYPE[item.type] ?? DEFAULT_BASE_PREMIUM;

const sumBasePremiums = (items: QuoteItem[]): number =>
  items.reduce((total, item) => total + basePremiumForItem(item), 0);

const quoteStep = (step: Step) => ({
  premium: sumBasePremiums(step.items) + PROCESSING_FEE,
});

export const runScenario = (scenario: unknown): unknown => {
  const { steps } = scenario as Scenario;
  return { results: steps.map(quoteStep) };
};

