import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Quote: base premiums and processing fee
  it("empty item list yields premium of 5 G (processing fee only)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result.results).toEqual([{ premium: 5 }]);
  });
  it("quote for a single plain sword yields 105 G (100 base + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result.results).toEqual([{ premium: 105 }]);
  });
  it("quote for a single plain amulet yields 65 G (60 base + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result.results).toEqual([{ premium: 65 }]);
  });
  it("quote for sword + amulet yields 165 G (100 + 60 + 5)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "sword", material: "steel", enchantment: 0, cursed: false },
            { type: "amulet", material: "silver", enchantment: 0, cursed: false },
          ],
        },
      ],
    });
    expect(result.results).toEqual([{ premium: 165 }]);
  });

  // Components
  it("quote for 2 runes yields 55 G (50 base + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(result.results).toEqual([{ premium: 55 }]);
  });
  it.todo("quote for 3 runes yields 65 G (60 G block + 5 fee)");
  it.todo("quote for 4 runes yields 105 G (100 base, no block + 5 fee)");
  it.todo("quote for 3 runes + 3 moonstones yields 125 G (two blocks 120 + 5)");

  // Premium modifiers (item-specific)
  it.todo("cursed sword adds 50% surcharge (newcomer cursed sword = 165 G)");
  it.todo("high enchantment (≥5) adds 30% surcharge to the affected item");

  // Premium modifiers (policy-wide)
  it.todo("long-standing customer (≥2 years) gets 20% loyalty discount on policy base");
  it.todo("follow-up contract gets 15% discount on policy base");
  it.todo("first insurance adds 10% surcharge per item");

  // Rounding
  it.todo("premium is rounded up to whole G (MHPCO's favor)");

  // Claim: standard reimbursement
  it.todo("claim with damage on plain sword reimburses full minus 100 G deductible");
  it.todo("remainingCap reflects payout deducted from 2x insurance sum");

  // Claim: special clauses
  it.todo("damage on enchantment ≥8 item is reimbursed at 50% then deductible");
  it.todo("damage on dragon material item is fully reimbursed (deductible only)");
  it.todo("dragon material + enchantment ≥8: 50% rule wins, then deductible");

  // Claim: multiple damages
  it.todo("multiple damage entries each apply their own deductible");

  // Claim: cap
  it.todo("cap is exhausted across successive claims");

  // Claim: rounding
  it.todo("payout is rounded down to whole G (MHPCO's favor)");

  // Validation / errors
  it.todo("unknown item type in quote throws an error");
  it.todo("claim damage for item not in policy throws an error");
  it.todo("negative damage amount throws an error");
});

