const PROCESSING_FEE = 5;
const DEFAULT_BASE_PREMIUM = 100;
const CURSE_SURCHARGE_RATE = 0.5;
const FIRST_INSURANCE_RATE = 0.1;

type QuoteItem = { type: string; material?: string; enchantment?: number; cursed?: boolean };
type Step = { op: string; items: QuoteItem[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
  amulet: 60,
  rune: 25,
  moonstone: 25,
};
const BLOCK_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_OF_THREE_BASE = 60;
const BLOCK_SIZE = 3;

const basePremiumForItem = (item: QuoteItem): number =>
  BASE_PREMIUM_BY_TYPE[item.type] ?? DEFAULT_BASE_PREMIUM;

const groupByType = (items: QuoteItem[]): Map<string, QuoteItem[]> =>
  items.reduce((groups, item) => {
    const group = groups.get(item.type) ?? [];
    return groups.set(item.type, [...group, item]);
  }, new Map<string, QuoteItem[]>());

const itemSurcharges = (item: QuoteItem, base: number): number => {
  const curse = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
  const firstInsurance = base * FIRST_INSURANCE_RATE;
  return curse + firstInsurance;
};

const itemPremium = (item: QuoteItem): number => {
  const base = basePremiumForItem(item);
  return base + itemSurcharges(item, base);
};

const groupPremium = (type: string, group: QuoteItem[]): number =>
  BLOCK_TYPES.has(type) && group.length === BLOCK_SIZE
    ? BLOCK_OF_THREE_BASE * (1 + FIRST_INSURANCE_RATE)
    : group.reduce((sum, item) => sum + itemPremium(item), 0);

const sumItemPremiums = (items: QuoteItem[]): number =>
  [...groupByType(items)].reduce(
    (total, [type, group]) => total + groupPremium(type, group),
    0,
  );

const quoteStep = (step: Step) => ({
  premium: sumItemPremiums(step.items) + PROCESSING_FEE,
});

export const runScenario = (scenario: unknown): unknown => {
  const { steps } = scenario as Scenario;
  return { results: steps.map(quoteStep) };
};

