const PROCESSING_FEE = 5;
const DEFAULT_BASE_PREMIUM = 100;
const CURSE_SURCHARGE_RATE = 0.5;
const FIRST_INSURANCE_RATE = 0.1;
const HIGH_ENCHANTMENT_RATE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const LOYALTY_DISCOUNT_RATE = 0.2;
const LOYALTY_THRESHOLD_YEARS = 2;

type QuoteItem = { type: string; material?: string; enchantment?: number; cursed?: boolean };
type Step = { op: string; items: QuoteItem[] };
type Customer = { yearsWithMHPCO: number };
type Scenario = { customer: Customer; steps: Step[] };

const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
  amulet: 60,
  rune: 25,
  moonstone: 25,
};
const BLOCK_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_OF_THREE_BASE = 60;
const BLOCK_SIZE = 3;

const basePremiumForItem = (item: QuoteItem): number =>
  BASE_PREMIUM_BY_TYPE[item.type] ?? DEFAULT_BASE_PREMIUM;

const groupByType = (items: QuoteItem[]): Map<string, QuoteItem[]> =>
  items.reduce((groups, item) => {
    const group = groups.get(item.type) ?? [];
    return groups.set(item.type, [...group, item]);
  }, new Map<string, QuoteItem[]>());

const isHighEnchantment = (item: QuoteItem): boolean =>
  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;

const itemSurchargeRate = (item: QuoteItem): number =>
  (item.cursed ? CURSE_SURCHARGE_RATE : 0) +
  (isHighEnchantment(item) ? HIGH_ENCHANTMENT_RATE : 0) +
  FIRST_INSURANCE_RATE;

const itemPremium = (item: QuoteItem): number => {
  const base = basePremiumForItem(item);
  return base + base * itemSurchargeRate(item);
};

const isBlockGroup = (type: string, group: QuoteItem[]): boolean =>
  BLOCK_TYPES.has(type) && group.length === BLOCK_SIZE;

const groupBase = (type: string, group: QuoteItem[]): number =>
  isBlockGroup(type, group)
    ? BLOCK_OF_THREE_BASE
    : group.reduce((sum, item) => sum + basePremiumForItem(item), 0);

const groupPremium = (type: string, group: QuoteItem[]): number =>
  isBlockGroup(type, group)
    ? BLOCK_OF_THREE_BASE * (1 + FIRST_INSURANCE_RATE)
    : group.reduce((sum, item) => sum + itemPremium(item), 0);

const sumOver = (
  items: QuoteItem[],
  groupFn: (type: string, group: QuoteItem[]) => number,
): number =>
  [...groupByType(items)].reduce(
    (total, [type, group]) => total + groupFn(type, group),
    0,
  );

const loyaltyDiscount = (customer: Customer, policyBase: number): number =>
  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? policyBase * LOYALTY_DISCOUNT_RATE : 0;

const quoteStep = (customer: Customer) => (step: Step) => {
  const policyBase = sumOver(step.items, groupBase);
  const premiumWithSurcharges = sumOver(step.items, groupPremium);
  return {
    premium: premiumWithSurcharges - loyaltyDiscount(customer, policyBase) + PROCESSING_FEE,
  };
};

export const runScenario = (scenario: unknown): unknown => {
  const { customer, steps } = scenario as Scenario;
  return { results: steps.map(quoteStep(customer)) };
};

