const PROCESSING_FEE = 5;
const DEFAULT_BASE_PREMIUM = 100;
const CURSE_SURCHARGE_RATE = 0.5;
const FIRST_INSURANCE_RATE = 0.1;
const HIGH_ENCHANTMENT_RATE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const LOYALTY_DISCOUNT_RATE = 0.2;
const LOYALTY_THRESHOLD_YEARS = 2;
const FOLLOW_UP_DISCOUNT_RATE = 0.15;

type QuoteItem = { type: string; material?: string; enchantment?: number; cursed?: boolean };
type Step = { op: string; items: QuoteItem[] };
type Customer = { yearsWithMHPCO: number };
type Scenario = { customer: Customer; steps: Step[] };

const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
  amulet: 60,
  rune: 25,
  moonstone: 25,
};
const BLOCK_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_OF_THREE_BASE = 60;
const BLOCK_SIZE = 3;

const basePremiumForItem = (item: QuoteItem): number =>
  BASE_PREMIUM_BY_TYPE[item.type] ?? DEFAULT_BASE_PREMIUM;

const groupByType = (items: QuoteItem[]): Map<string, QuoteItem[]> =>
  items.reduce((groups, item) => {
    const group = groups.get(item.type) ?? [];
    return groups.set(item.type, [...group, item]);
  }, new Map<string, QuoteItem[]>());

const isHighEnchantment = (item: QuoteItem): boolean =>
  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;

const itemSurchargeRate = (item: QuoteItem): number =>
  (item.cursed ? CURSE_SURCHARGE_RATE : 0) +
  (isHighEnchantment(item) ? HIGH_ENCHANTMENT_RATE : 0) +
  FIRST_INSURANCE_RATE;

const itemPremium = (item: QuoteItem): number => {
  const base = basePremiumForItem(item);
  return base + base * itemSurchargeRate(item);
};

const isBlockGroup = (type: string, group: QuoteItem[]): boolean =>
  BLOCK_TYPES.has(type) && group.length === BLOCK_SIZE;

const groupBase = (type: string, group: QuoteItem[]): number =>
  isBlockGroup(type, group)
    ? BLOCK_OF_THREE_BASE
    : group.reduce((sum, item) => sum + basePremiumForItem(item), 0);

const groupPremium = (type: string, group: QuoteItem[]): number =>
  isBlockGroup(type, group)
    ? BLOCK_OF_THREE_BASE * (1 + FIRST_INSURANCE_RATE)
    : group.reduce((sum, item) => sum + itemPremium(item), 0);

const sumOver = (
  items: QuoteItem[],
  groupFn: (type: string, group: QuoteItem[]) => number,
): number =>
  [...groupByType(items)].reduce(
    (total, [type, group]) => total + groupFn(type, group),
    0,
  );

const loyaltyDiscount = (customer: Customer, policyBase: number): number =>
  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? policyBase * LOYALTY_DISCOUNT_RATE : 0;

const followUpDiscount = (quoteIndex: number, policyBase: number): number =>
  quoteIndex > 0 ? policyBase * FOLLOW_UP_DISCOUNT_RATE : 0;

const quoteStep = (customer: Customer, quoteIndex: number) => (step: Step) => {
  const policyBase = sumOver(step.items, groupBase);
  const premiumWithSurcharges = sumOver(step.items, groupPremium);
  return {
    premium:
      premiumWithSurcharges -
      loyaltyDiscount(customer, policyBase) -
      followUpDiscount(quoteIndex, policyBase) +
      PROCESSING_FEE,
  };
};

export const runScenario = (scenario: unknown): unknown => {
  const { customer, steps } = scenario as Scenario;
  const { results } = steps.reduce(
    (acc, step) => ({
      results: [...acc.results, quoteStep(customer, acc.quoteIndex)(step)],
      quoteIndex: acc.quoteIndex + (step.op === "quote" ? 1 : 0),
    }),
    { results: [] as { premium: number }[], quoteIndex: 0 },
  );
  return { results };
};

import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Quote: base premiums and processing fee
  it("empty item list yields premium of 5 G (processing fee only)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result.results).toEqual([{ premium: 5 }]);
  });
  it("quote for a single plain sword yields 115 G (100 base + 10 first insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result.results).toEqual([{ premium: 115 }]);
  });
  it("quote for a single plain amulet yields 71 G (60 + 6 first insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result.results).toEqual([{ premium: 71 }]);
  });
  it("quote for sword + amulet yields 181 G (110 + 66 + 5)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "sword", material: "steel", enchantment: 0, cursed: false },
            { type: "amulet", material: "silver", enchantment: 0, cursed: false },
          ],
        },
      ],
    });
    expect(result.results).toEqual([{ premium: 181 }]);
  });

  // Components
  it("quote for 2 runes yields 60 G (50 base + 5 first ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(result.results).toEqual([{ premium: 60 }]);
  });
  it("quote for 3 runes yields 71 G (60 G block + 6 first ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(result.results).toEqual([{ premium: 71 }]);
  });
  it("quote for 4 runes yields 115 G (100 base, no block + 10 first ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(result.results).toEqual([{ premium: 115 }]);
  });
  it("quote for 3 runes + 3 moonstones yields 137 G (two blocks 120 + 12 first ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
            { type: "moonstone" },
            { type: "moonstone" },
            { type: "moonstone" },
          ],
        },
      ],
    });
    expect(result.results).toEqual([{ premium: 137 }]);
  });

  // Premium modifiers (item-specific)
  it("cursed sword adds 50% surcharge (newcomer cursed sword = 165 G)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: true }],
        },
      ],
    });
    expect(result.results).toEqual([{ premium: 165 }]);
  });
  it("high enchantment (≥5) adds 30% surcharge to the affected item", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 5, cursed: false }],
        },
      ],
    });
    expect(result.results).toEqual([{ premium: 145 }]);
  });

  // Premium modifiers (policy-wide)
  it("long-standing customer (≥2 years) gets 20% loyalty discount on policy base", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 2 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        },
      ],
    });
    // 100 base - 20 loyalty + 10 first insurance + 5 fee = 95
    expect(result.results).toEqual([{ premium: 95 }]);
  });
  it("follow-up contract gets 15% discount on policy base", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        },
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        },
      ],
    });
    // First: 115 G (100 base + 10 first ins + 5 fee)
    // Second: 100 G (100 base - 15 follow-up + 10 first ins + 5 fee)
    expect(result.results).toEqual([{ premium: 115 }, { premium: 100 }]);
  });
  it.todo("first insurance adds 10% surcharge per item");

  // Rounding
  it.todo("premium is rounded up to whole G (MHPCO's favor)");

  // Claim: standard reimbursement
  it.todo("claim with damage on plain sword reimburses full minus 100 G deductible");
  it.todo("remainingCap reflects payout deducted from 2x insurance sum");

  // Claim: special clauses
  it.todo("damage on enchantment ≥8 item is reimbursed at 50% then deductible");
  it.todo("damage on dragon material item is fully reimbursed (deductible only)");
  it.todo("dragon material + enchantment ≥8: 50% rule wins, then deductible");

  // Claim: multiple damages
  it.todo("multiple damage entries each apply their own deductible");

  // Claim: cap
  it.todo("cap is exhausted across successive claims");

  // Claim: rounding
  it.todo("payout is rounded down to whole G (MHPCO's favor)");

  // Validation / errors
  it.todo("unknown item type in quote throws an error");
  it.todo("claim damage for item not in policy throws an error");
  it.todo("negative damage amount throws an error");
});

