          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(result.results).toEqual([{ premium: 71 }]);
  });
  it("quote for 4 runes yields 115 G (100 base, no block + 10 first ins + 5 fee)", () => {
